346	// legacySkillSymlinkDirs returns the relative names of skill directories
347	// (e.g. ".agents/skills", ".claude/skills") under workingDir that contain
348	// at least one symlink. A symlink indicates a pre-FEAT-015 install.
349	func legacySkillSymlinkDirs(workingDir string) []string {
350		if workingDir == "" {
351			return nil
352		}
353		var found []string
354		for _, rel := range []string{".agents/skills", ".claude/skills"} {
355			dir := filepath.Join(workingDir, rel)
356			entries, err := os.ReadDir(dir)
357			if err != nil {
358				continue
359			}
360			for _, e := range entries {
361				info, err := e.Info()
362				if err != nil {
363					continue
364				}
365				if info.Mode()&os.ModeSymlink != 0 {
366					found = append(found, rel)
367					break
368				}
369			}
370		}
371		return found
372	}
