374	// checkBinaryInstallLocation verifies the running binary is at the canonical install
375	// location ($HOME/.local/bin/ddx) and scans PATH for other ddx copies whose
376	// SHA-256 differs from the running binary.
377	func checkBinaryInstallLocation(executable string) []DiagnosticIssue {
378		var issues []DiagnosticIssue
379	
380		homeDir, err := os.UserHomeDir()
381		if err != nil {
382			return issues
383		}
384	
385		canonicalPath := filepath.Join(homeDir, ".local", "bin", "ddx")
386	
387		// (2) Check whether running binary matches the canonical install location.
388		resolvedExec, _ := filepath.EvalSymlinks(executable)
389		if resolvedExec == "" {
390			resolvedExec = executable
391		}
392		resolvedCanonical, _ := filepath.EvalSymlinks(canonicalPath)
393		execMatchesCanonical := resolvedExec == canonicalPath ||
394			(resolvedCanonical != "" && resolvedExec == resolvedCanonical)
395		if !execMatchesCanonical {
396			issues = append(issues, DiagnosticIssue{
397				Type:        "binary_not_canonical",
398				Description: fmt.Sprintf("Running binary (%s) is not at canonical install location (%s)", executable, canonicalPath),
399				Remediation: []string{
400					"Re-run install.sh to reinstall to the canonical location",
401					fmt.Sprintf("Or ensure %s is earlier in your PATH", filepath.Dir(canonicalPath)),
402				},
403			})
404		}
405	
406		// (3) Walk PATH and flag any ddx copy whose SHA-256 differs from the running binary.
407		runningSHA, err := computeFileSHA256(executable)
408		if err != nil {
409			return issues
410		}
411	
412		seen := make(map[string]bool)
413		for _, dir := range filepath.SplitList(os.Getenv("PATH")) {
414			candidate := filepath.Join(dir, "ddx")
415			if seen[candidate] {
416				continue
417			}
418			seen[candidate] = true
419	
420			info, err := os.Stat(candidate)
421			if err != nil || !info.Mode().IsRegular() || info.Mode()&0111 == 0 {
422				continue
423			}
424	
425			candidateSHA, err := computeFileSHA256(candidate)
426			if err != nil {
427				continue
428			}
429	
430			if candidateSHA == runningSHA {
431				continue // same binary, not stale
432			}
433	
434			issues = append(issues, DiagnosticIssue{
435				Type:        "binary_sha_mismatch",
436				Description: fmt.Sprintf("Stale ddx copy on PATH: %s (SHA-256 differs from running binary)", candidate),
437				Remediation: []string{
438					fmt.Sprintf("rm %s && cp %s %s", candidate, executable, candidate),
439					"Or re-run install.sh to update all copies",
440				},
441			})
442		}
443	
444		return issues
445	}
