447	// computeFileSHA256 returns the hex-encoded SHA-256 digest of the named file.
448	func computeFileSHA256(path string) (string, error) {
449		f, err := os.Open(path)
450		if err != nil {
451			return "", err
452		}
453		defer f.Close()
454	
455		h := sha256.New()
456		if _, err := io.Copy(h, f); err != nil {
457			return "", err
458		}
459		return hex.EncodeToString(h.Sum(nil)), nil
460	}
