496	type proseCheckerStatus struct {
497		Path    string
498		Version string
499		Issue   *DiagnosticIssue
500	}
501	
502	func checkProseChecker() proseCheckerStatus {
503		path, err := exec.LookPath("vale")
504		if err != nil {
505			return proseCheckerStatus{
506				Issue: proseCheckerIssue("Vale prose checker is not installed or is not on PATH"),
507			}
508		}
509	
510		ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
511		defer cancel()
512	
513		output, err := exec.CommandContext(ctx, path, "--version").CombinedOutput()
514		version := strings.TrimSpace(string(output))
515		if err != nil {
516			desc := fmt.Sprintf("Vale prose checker did not report a supported version; expected %q", supportedValeVersion)
517			if version != "" {
518				desc += fmt.Sprintf("; got %q", version)
519			}
520			desc += fmt.Sprintf("; error: %v", err)
521			return proseCheckerStatus{
522				Path:    path,
523				Version: version,
524				Issue:   proseCheckerIssue(desc),
525			}
526		}
527		if version != supportedValeVersion {
528			if version == "" {
529				version = "<empty>"
530			}
531			return proseCheckerStatus{
532				Path:    path,
533				Version: version,
534				Issue: proseCheckerIssue(
535					fmt.Sprintf("Unsupported Vale prose checker version %q; expected %q", version, supportedValeVersion),
536				),
537			}
538		}
539	
540		return proseCheckerStatus{
541			Path:    path,
542			Version: version,
543		}
544	}
