586	// checkLibraryPath verifies library path is accessible
587	func checkLibraryPathFromWorkingDir(workingDir string) bool {
588		cfg, err := config.LoadWithWorkingDir(workingDir)
589		if err != nil {
590			return false
591		}
592	
593		if cfg.Library == nil || cfg.Library.Path == "" {
594			return false
595		}
596	
597		// Resolve library path relative to working directory
598		libPath := cfg.Library.Path
599		if !filepath.IsAbs(libPath) {
600			libPath = filepath.Join(workingDir, libPath)
601		}
602	
603		_, err = os.Stat(libPath)
604		return err == nil
605	}
