623	// generateDiagnosticReport creates a detailed diagnostic report
624	func generateDiagnosticReport(issues []DiagnosticIssue, verbose bool, workingDir string) {
625		if len(issues) == 0 && !verbose {
626			return
627		}
628	
629		fmt.Println()
630		fmt.Println("📊 DETAILED DIAGNOSTIC REPORT")
631		fmt.Println("========================================")
632	
633		if verbose {
634			fmt.Println()
635			fmt.Println("🔍 System Information:")
636			fmt.Printf("  OS: %s\n", runtime.GOOS)
637			fmt.Printf("  Architecture: %s\n", runtime.GOARCH)
638			fmt.Printf("  Go Runtime: %s\n", runtime.Version())
