715	// have a working launcher in the target path (e.g. ~/.local/bin/helix).
716	func checkInstalledLaunchers(verbose bool) {
717		state, err := registry.LoadState()
718		if err != nil || len(state.Installed) == 0 {
719			return
720		}
721	
722		reg := registry.BuiltinRegistry()
723		for _, entry := range state.Installed {
724			pkg, err := reg.Find(entry.Name)
725			if err != nil || pkg.Install.Scripts == nil {
726				continue
727			}
728	
729			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
730			name := filepath.Base(dst)
731			fmt.Printf("✓ Checking %s launcher... ", name)
732	
733			li, err := os.Lstat(dst)
734			if os.IsNotExist(err) {
735				fmt.Printf("❌ MISSING (%s not found, run: ddx install %s)\n", dst, pkg.Name)
736				continue
737			}
738			if err != nil {
739				fmt.Printf("❌ error: %v\n", err)
740				continue
741			}
742	
743			if li.Mode()&os.ModeSymlink != 0 {
744				target, _ := os.Readlink(dst)
745				if verbose {
746					fmt.Printf("✅ OK (developer symlink → %s)\n", target)
747				} else {
748					fmt.Println("✅ OK (developer symlink)")
749				}
750				continue
751			}
752	
753			// Regular file — check it's executable.
754			if li.Mode()&0111 != 0 {
755				fmt.Printf("✅ OK (%s)\n", dst)
756			} else {
757				fmt.Printf("⚠️  not executable (run: chmod +x %s)\n", dst)
