762	// checkInstalledPlugins audits installed plugin roots and manifests.
763	func checkInstalledPlugins(verbose bool) []DiagnosticIssue {
764		state, err := registry.LoadState()
765		if err != nil || len(state.Installed) == 0 {
766			return nil
767		}
768	
769		reg := registry.BuiltinRegistry()
770		var issues []DiagnosticIssue
771	
772		for _, entry := range state.Installed {
773			fallback, _ := reg.Find(entry.Name)
774			entryType := entry.Type
775			if entryType == "" && fallback != nil {
776				entryType = fallback.Type
777			}
778			if entryType == "" && !looksLikePluginInstall(entry) {
779				continue
780			}
781			switch entryType {
782			case registry.PackageTypePlugin, registry.PackageTypeWorkflow:
783			case "":
784			default:
785				continue
786			}
787			for _, issue := range registry.AuditInstalledEntry(entry, fallback) {
788				diag := DiagnosticIssue{
789					Type:        "plugin_validation",
790					Description: issue.Error(),
791					Remediation: []string{
792						"Check package.yaml, skill directories, and installed symlinks for the path shown above",
793						"Reinstall the package after fixing the source tree or manifest",
794					},
795					SystemInfo: map[string]string{
796						"plugin": entry.Name,
797					},
798				}
799				if verbose {
800					diag.SystemInfo["source"] = entry.Source
801				}
802				issues = append(issues, diag)
803			}
804		}
805	
806		return issues
807	}
