809	func looksLikePluginInstall(entry registry.InstalledEntry) bool {
810		candidates := make([]string, 0, 2+len(entry.Files))
811		if root := installedEntryRootCandidate(entry); root != "" {
812			candidates = append(candidates, root)
813		}
814		candidates = append(candidates, entry.Files...)
815	
816		for _, candidate := range candidates {
817			path := registry.ExpandHome(strings.TrimSpace(candidate))
818			if path == "" {
819				continue
820			}
821	
822			info, err := os.Lstat(path)
823			if err != nil {
824				continue
825			}
826	
827			if info.IsDir() || info.Mode()&os.ModeSymlink != 0 {
828				return true
829			}
830		}
831	
832		return false
833	}
