835	func installedEntryRootCandidate(entry registry.InstalledEntry) string {
836		if len(entry.Files) > 0 && strings.TrimSpace(entry.Files[0]) != "" {
837			return entry.Files[0]
838		}
839		return strings.TrimSpace(entry.Source)
840	}
