842	// checkGitRepoHealth detects git-repo corruption from prior ddx incidents:
843	//  1. core.bare=true on a repo that has a working tree (not actually bare)
844	//  2. Stray core.worktree that does not match the actual toplevel
845	//  3. Local core.hooksPath that prevents lefthook from managing hook sync
846	//  4. extensions.worktreeConfig not enabled (warning only)
847	//
848	// If fix is true, conditions (1), (2), and (3) are remediated with git config unset.
849	// (4) is always a warning — never auto-fixed, since enabling per-worktree config
850	// is a user-facing choice.
851	func checkGitRepoHealth(workingDir string, fix bool) []DiagnosticIssue {
852		var issues []DiagnosticIssue
853		ctx := context.Background()
854	
855		// Bail out quietly if this directory isn't a git repo at all. We can't rely
856		// on `--is-inside-work-tree` here because the corruption we're looking for
857		// (core.bare=true on a repo that has a working tree) causes git to report
858		// "false" for that query. Instead, probe `--git-dir`, which succeeds on both
859		// bare and non-bare repos.
860		gitDirProbe := gitpkg.Command(ctx, workingDir, "rev-parse", "--git-dir")
861		gdOut, err := gitDirProbe.Output()
862		if err != nil {
863			return nil
864		}
865		gitDirRaw := strings.TrimSpace(string(gdOut))
866		if gitDirRaw == "" {
867			return nil
868		}
869	
870		// A "real" working tree on disk: either .git is a directory/file at
871		// workingDir, or git reports a separate work-tree via --show-toplevel.
872		// If neither holds, this is a genuinely bare repo → skip the checks.
873		hasWorkTreeOnDisk := false
874		if _, statErr := os.Stat(filepath.Join(workingDir, ".git")); statErr == nil {
875			hasWorkTreeOnDisk = true
876		}
877		if !hasWorkTreeOnDisk {
878			// Maybe we're inside a linked worktree where git treats us normally.
879			inWT := gitpkg.Command(ctx, workingDir, "rev-parse", "--is-inside-work-tree")
880			if b, err := inWT.Output(); err == nil && strings.TrimSpace(string(b)) == "true" {
881				hasWorkTreeOnDisk = true
882			}
883		}
884		if !hasWorkTreeOnDisk {
885			return nil
886		}
887	
888		gitConfigValue := func(key string) (string, bool) {
889			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--get", key)
890			b, err := c.Output()
891			if err != nil {
892				return "", false
893			}
894			return strings.TrimSpace(string(b)), true
895		}
896		gitConfigUnset := func(key string) error {
897			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--unset", key)
898			return c.Run()
899		}
900		gitConfigUnsetAll := func(key string) error {
901			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--unset-all", key)
902			return c.Run()
903		}
904	
905		// (1) core.bare=true on a repo with a working tree → corruption.
906		if val, ok := gitConfigValue("core.bare"); ok && val == "true" {
907			desc := "core.bare=true is set on a repository that has a working tree (not actually bare)"
908			rem := []string{"git config --unset core.bare"}
909			if fix {
910				if err := gitConfigUnset("core.bare"); err == nil {
911					desc += " — removed"
912				} else {
913					desc += fmt.Sprintf(" — unset failed: %v", err)
914				}
915			}
916			issues = append(issues, DiagnosticIssue{
917				Type:        "git_core_bare_corruption",
918				Description: desc,
919				Remediation: rem,
920			})
921		}
922	
923		// (2) Stray core.worktree that doesn't match the directory we're running
924		// against. Compare to workingDir directly — asking git for --show-toplevel
925		// would just echo back core.worktree.
926		if worktreeVal, ok := gitConfigValue("core.worktree"); ok && worktreeVal != "" {
927			actual := workingDir
928	
929			cmpVal := worktreeVal
930			if !filepath.IsAbs(cmpVal) {
931				cmpVal = filepath.Clean(filepath.Join(gitDirRaw, worktreeVal))
932			}
933			resolvedCmp, _ := filepath.EvalSymlinks(cmpVal)
934			if resolvedCmp == "" {
935				resolvedCmp = cmpVal
936			}
937			resolvedActual, _ := filepath.EvalSymlinks(actual)
938			if resolvedActual == "" {
939				resolvedActual = actual
940			}
941	
942			if actual != "" && resolvedCmp != resolvedActual {
943				desc := fmt.Sprintf("core.worktree=%q does not match actual worktree %q", worktreeVal, actual)
944				rem := []string{"git config --unset core.worktree"}
945				if fix {
946					if err := gitConfigUnset("core.worktree"); err == nil {
947						desc += " — removed"
948					} else {
949						desc += fmt.Sprintf(" — unset failed: %v", err)
950					}
951				}
952				issues = append(issues, DiagnosticIssue{
953					Type:        "git_stray_core_worktree",
954					Description: desc,
955					Remediation: rem,
956				})
957			}
958		}
959	
960		// (3) Local core.hooksPath interferes with lefthook's hook-path sync.
961		if hooksPathVal, ok := gitConfigValue("core.hooksPath"); ok && hooksPathVal != "" {
962			desc := fmt.Sprintf("core.hooksPath=%q is set locally; lefthook may skip hook-path sync and run stale hooks", hooksPathVal)
963			rem := []string{
964				"git config --unset-all --local core.hooksPath",
965				"lefthook install --reset-hooks-path",
966			}
967			if fix {
968				if err := gitConfigUnsetAll("core.hooksPath"); err == nil {
969					desc += " — removed"
970				} else {
971					desc += fmt.Sprintf(" — unset failed: %v", err)
972				}
973			}
974			issues = append(issues, DiagnosticIssue{
975				Type:        "git_local_hooks_path",
976				Description: desc,
977				Remediation: rem,
978			})
979		}
980	
981		// (4) extensions.worktreeConfig not enabled → warning only.
982		val, ok := gitConfigValue("extensions.worktreeConfig")
983		if !ok || val != "true" {
984			issues = append(issues, DiagnosticIssue{
985				Type:        "git_worktree_config_disabled",
986				Description: "extensions.worktreeConfig is not enabled; per-worktree config changes can corrupt the shared .git/config",
987				Remediation: []string{
988					"git config extensions.worktreeConfig true",
989				},
990			})
991		}
992	
993		return issues
994	}
