996	// packageJSONCheck holds the result of scanning one package.json location.
997	type packageJSONCheck struct {
998		Dir      string // relative path from project root (e.g. "website")
999		HasPkg   bool   // package.json exists
1000		NeedsBun bool   // node_modules missing or stale vs bun.lock
1001		Reason   string // "missing" | "stale"
1002	}
1003	
1004	// knownPackageJSONDirs are the subdirectories (relative to workingDir) that
1005	// may contain a package.json. "" means the repo root itself.
1006	var knownPackageJSONDirs = []string{"", "website", "cli/internal/server/frontend"}
1007	
1008	// checkPackageJSONLocations scans the known package.json locations under
1009	// workingDir and returns a DiagnosticIssue for each location where
1010	// node_modules/ is absent or older than bun.lock.
1011	func checkPackageJSONLocations(workingDir string) []DiagnosticIssue {
1012		var issues []DiagnosticIssue
1013	
1014		for _, rel := range knownPackageJSONDirs {
1015			var dir string
1016			if rel == "" {
1017				dir = workingDir
1018			} else {
1019				dir = filepath.Join(workingDir, filepath.FromSlash(rel))
1020			}
1021	
1022			pkgPath := filepath.Join(dir, "package.json")
1023			if _, err := os.Stat(pkgPath); err != nil {
1024				continue // no package.json here
1025			}
1026	
1027			label := rel
1028			if label == "" {
1029				label = "(repo root)"
1030			}
1031	
1032			nmPath := filepath.Join(dir, "node_modules")
1033			nmInfo, nmErr := os.Stat(nmPath)
1034			if nmErr != nil {
1035				// node_modules missing entirely
1036				issues = append(issues, DiagnosticIssue{
1037					Type:        "node_modules_missing",
1038					Description: fmt.Sprintf("node_modules/ missing in %s", label),
1039					Remediation: []string{
1040						fmt.Sprintf("cd %s && bun install", dir),
1041					},
1042					SystemInfo: map[string]string{"package_json": pkgPath},
1043				})
1044				continue
1045			}
1046	
1047			// Check if bun.lock is newer than node_modules
1048			lockPath := filepath.Join(dir, "bun.lock")
1049			lockInfo, lockErr := os.Stat(lockPath)
1050			if lockErr == nil && lockInfo.ModTime().After(nmInfo.ModTime()) {
1051				issues = append(issues, DiagnosticIssue{
1052					Type:        "node_modules_stale",
1053					Description: fmt.Sprintf("node_modules/ in %s is older than bun.lock (run bun install)", label),
1054					Remediation: []string{
1055						fmt.Sprintf("cd %s && bun install", dir),
1056					},
1057					SystemInfo: map[string]string{"package_json": pkgPath},
1058				})
1059			}
1060		}
1061	
1062		return issues
1063	}
