1065	// checkMetaPromptSync checks if the meta-prompt in CLAUDE.md is in sync with library
1066	func checkMetaPromptSync(workingDir string) error {
1067		cfg, err := config.LoadWithWorkingDir(workingDir)
1068		if err != nil {
1069			// Can't load config - skip check
1070			return nil
1071		}
1072	
1073		promptPath := cfg.GetMetaPrompt()
1074		if promptPath == "" {
1075			// Meta-prompt disabled - not an issue
1076			return nil
1077		}
1078	
1079		injector := metaprompt.NewMetaPromptInjectorWithPaths(
1080			"CLAUDE.md",
1081			cfg.Library.Path,
1082			workingDir,
1083		)
1084	
1085		inSync, err := injector.IsInSync()
1086		if err != nil {
1087			// Could not check (file missing, etc) - not a critical issue
1088			return nil
1089		}
1090	
1091		if !inSync {
1092			return fmt.Errorf("meta-prompt is out of sync with library")
1093		}
1094	
1095		return nil
1096	}
